
'use client';

import { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Route, MapPin } from "lucide-react";
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { Separator } from '@/components/ui/separator';
import { Badge } from '@/components/ui/badge';
import Image from "next/image";

const initialRouteStops = [
    { id: 'stop1', name: '123 Maple St', time: '8:15 AM', status: 'Upcoming', completed: false },
    { id: 'stop2', name: '456 Oak Ave', time: '8:22 AM', status: 'Upcoming', completed: false },
    { id: 'stop3', name: 'Elm St & Pine Ln', time: '8:30 AM', status: 'Upcoming', completed: false },
    { id: 'stop4', name: 'Springfield Elementary', time: '8:45 AM', status: 'Upcoming', completed: false },
];

export default function MyRoutePage() {
  const [routeStops, setRouteStops] = useState(initialRouteStops);

  const handleStopCompletion = (stopId: string, isCompleted: boolean | 'indeterminate') => {
    setRouteStops(stops => 
      stops.map(stop => 
        stop.id === stopId ? { ...stop, completed: !!isCompleted, status: isCompleted ? 'Completed' : 'Upcoming' } : stop
      )
    );
  };

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-bold font-headline">My Route Details</h1>
        <p className="text-muted-foreground">Manually track your progress through the North Route for today.</p>
      </div>

      <div className="grid gap-8 md:grid-cols-2">
        <Card>
            <CardHeader>
                <CardTitle className="flex items-center gap-2"><Route className="h-5 w-5 text-primary" /> North Route Checklist</CardTitle>
                 <CardDescription>Check off each stop as you complete it.</CardDescription>
            </CardHeader>
            <CardContent>
                 <div className="space-y-4">
                    {routeStops.map((stop, index) => (
                        <div key={stop.id}>
                          <div className="flex items-center gap-4">
                              <Checkbox 
                                id={stop.id}
                                checked={stop.completed}
                                onCheckedChange={(checked) => handleStopCompletion(stop.id, checked)}
                                className="h-6 w-6"
                              />
                              <Label htmlFor={stop.id} className="flex-1 cursor-pointer">
                                  <div className="flex justify-between items-center">
                                      <div>
                                          <p className={`font-medium ${stop.completed ? 'line-through text-muted-foreground' : ''}`}>{stop.name}</p>
                                          <p className={`text-sm text-muted-foreground ${stop.completed ? 'line-through' : ''}`}>ETA: {stop.time}</p>
                                      </div>
                                      <Badge variant={stop.completed ? 'secondary' : 'outline'} className={!stop.completed ? 'text-primary border-primary' : ''}>
                                        {stop.completed ? 'Completed' : 'Upcoming'}
                                      </Badge>
                                  </div>
                              </Label>
                          </div>
                          {index < routeStops.length - 1 && <Separator className="mt-4" />}
                        </div>
                    ))}
                 </div>
            </CardContent>
        </Card>
        <Card>
             <CardHeader>
                <CardTitle className="flex items-center gap-2"><MapPin className="h-5 w-5 text-primary" /> Route Map</CardTitle>
                <CardDescription>Visual representation of your route stops.</CardDescription>
            </CardHeader>
            <CardContent>
               <div className="h-[400px] w-full bg-muted rounded-lg overflow-hidden">
                 <Image
                    src="https://placehold.co/600x400.png"
                    alt="A map showing the bus route"
                    width={600}
                    height={400}
                    className="w-full h-full object-cover"
                    data-ai-hint="map route"
                  />
               </div>
            </CardContent>
        </Card>
      </div>

    </div>
  );
}
